# Violation: one class has three responsibilities — data, formatting, and persistence
class Report:
    def __init__(self, title, content):
        self.title = title  # Report title
        self.content = content  # Report body text

    def format_html(self):
        # Responsibility 1: formatting the report as HTML
        return f"<h1>{self.title}</h1><p>{self.content}</p>"

    def save_to_file(self, filename):
        # Responsibility 2: persisting the report to disk (different concern!)
        with open(filename, "w") as f:
            f.write(self.format_html())

# Fix: separate classes with single responsibilities
class Report:
    # Only responsible for holding report data
    def __init__(self, title, content):
        self.title = title
        self.content = content

class HTMLFormatter:
    # Only responsible for formatting reports as HTML
    def format(self, report: Report) -> str:
        return f"<h1>{report.title}</h1><p>{report.content}</p>"

class FileStorage:
    # Only responsible for saving data to files
    def save(self, filename: str, data: str) -> None:
        with open(filename, "w") as f:
            f.write(data)

# Usage — each class does one thing well
report = Report("Q3 Results", "Revenue increased 15%")
formatter = HTMLFormatter()
storage = FileStorage()
html = formatter.format(report)
storage.save("report.html", html)
